body = []
spikes = []
title = []
objs = []

for i,svg in enumerate(svgs):
    svg_obj = dpl.svg(data=svg['path'],**styles[svg['style']])
    if svg['style'] == 0:
        obj = {'name': 'spike ' + str(len(spikes)),'object':svg_obj}
        spikes.append(svg_obj)
    elif svg['style'] == 3:
        obj = {'name': 'title ' + str(len(title)),'object':svg_obj}
        title.append(svg_obj)
    else:
        obj = {'name': 'body ' + str(len(body)),'object':svg_obj}
        body.append(svg_obj)
    objs.append(obj)

seq = dpl.Sequence(fig=fig,transparent=True,white=True)

GUI = dpl.GUI.GUI(seq=seq,plot_objects=objs)
GUI.open()